import{_ as a,o as t,c as n,ag as s}from"./chunks/framework.ePeAWSvT.js";const m=JSON.parse('{"title":"Agent 模块","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/agent.md","filePath":"guide/architecture/agent.md"}'),o={name:"guide/architecture/agent.md"};function p(l,e,r,d,c,i){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="agent-模块" tabindex="-1">Agent 模块 <a class="header-anchor" href="#agent-模块" aria-label="Permalink to &quot;Agent 模块&quot;">​</a></h1><p><code>src/lab/agent/</code> — LLM 调用、工具循环、记忆管理。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent/</span></span>
<span class="line"><span>├── agent_factory.py          # AgentFactory：根据配置创建 AgentCore / Agent 实例</span></span>
<span class="line"><span>├── core.py                   # AgentCore：共享核心逻辑（tool calling / vision / prompt / storage）</span></span>
<span class="line"><span>├── storage.py                # ConversationStorage Protocol + 两种实现</span></span>
<span class="line"><span>├── types.py                  # 核心类型定义（OpenAIMessage / ContentPart / ConversationState 等）</span></span>
<span class="line"><span>├── stateless_llm_factory.py  # LLMFactory：创建 OpenAI Compatible LLM 实例</span></span>
<span class="line"><span>├── stateless_llm/</span></span>
<span class="line"><span>│   └── openai_compatible_llm.py  # AsyncLLM：异步流式 LLM 调用（含 stream_with_tools）</span></span>
<span class="line"><span>├── input_types.py            # 输入类型（BatchInput / ImageData / TextData）</span></span>
<span class="line"><span>├── output_types.py           # 输出类型（SentenceOutput / AudioOutput / Actions）</span></span>
<span class="line"><span>├── transformers.py           # 文本后处理管线（断句、表情提取、TTS 过滤）</span></span>
<span class="line"><span>└── agents/</span></span>
<span class="line"><span>    ├── agent_interface.py    # AgentInterface：抽象基类</span></span>
<span class="line"><span>    └── memory_agent/         # MemoryAgent：当前唯一实现</span></span>
<span class="line"><span>        ├── agent.py          # 编排器（orchestrator）</span></span>
<span class="line"><span>        ├── memory_store.py   # 内存消息列表 + 历史读写</span></span>
<span class="line"><span>        ├── message_factory.py # OpenAI Message 构造</span></span>
<span class="line"><span>        ├── prompt_builder.py  # UserPromptBlock 拼装</span></span>
<span class="line"><span>        ├── user_prompt_block.py # UserPromptBlock 数据结构</span></span>
<span class="line"><span>        ├── vision_summarizer.py # 图片摘要生成</span></span>
<span class="line"><span>        └── types.py           # 内部类型（ImagePayload 等）</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="agentcore" tabindex="-1">AgentCore <a class="header-anchor" href="#agentcore" aria-label="Permalink to &quot;AgentCore&quot;">​</a></h3><p><code>AgentCore</code>（<code>core.py</code>）是 MemoryAgent 和 <code>/memory/chat</code> 的<strong>共享核心</strong>，统一实现了：</p><h3 id="核心类型-types-py" tabindex="-1">核心类型（<code>types.py</code>） <a class="header-anchor" href="#核心类型-types-py" aria-label="Permalink to &quot;核心类型（\`types.py\`）&quot;">​</a></h3><p>原 <code>src/lab/mcp/_typing.py</code> + <code>util.py</code> 迁移至此，被整个 <code>agent/</code> 及 <code>tools/</code> 广泛使用：</p><table tabindex="0"><thead><tr><th>类型 / 函数</th><th>说明</th></tr></thead><tbody><tr><td><code>OpenAIMessage</code></td><td>OpenAI messages 格式（role / content / tool_call_id / name）</td></tr><tr><td><code>TextPart</code> / <code>ImagePart</code> / <code>AudioPart</code> / <code>FilePart</code></td><td>多模态 content 类型</td></tr><tr><td><code>ContentPart</code></td><td>上述类型的 Union</td></tr><tr><td><code>ConversationState</code></td><td>对话状态容器（messages / refs / slots / active_task）</td></tr><tr><td><code>ToolCallLike</code></td><td>OpenAI tool_call Protocol（id / function.name / function.arguments）</td></tr><tr><td><code>ToolTraceItem</code></td><td>工具调用 trace（server / name / args / raw_result / ok / error）</td></tr><tr><td><code>ScreenShotResult</code> / <code>ImageRefResult</code></td><td>截图工具返回类型</td></tr><tr><td><code>call_with_short_retry</code></td><td>带短暂重试的异步调用包装（LLM API 调用）</td></tr><tr><td><code>dump_openai_msg</code></td><td>将 <code>OpenAIMessage</code> 序列化为可读 dict（调试用）</td></tr><tr><td><code>normalize_jsonlike</code></td><td>将类 JSON 对象规范化为标准 dict</td></tr></tbody></table><ul><li>流式 Tool Calling（<code>chat_llm</code> 原生，多轮循环，无独立 tool model）</li><li>Vision 预处理（<code>VisionSummarizer</code>）</li><li>Prompt 拼装（<code>PromptBuilder</code>）</li><li>历史存储（<code>ConversationStorage</code>）</li></ul><p>详见 <a href="./agent-core.html">AgentCore 架构</a>。</p><h3 id="agentinterface" tabindex="-1">AgentInterface <a class="header-anchor" href="#agentinterface" aria-label="Permalink to &quot;AgentInterface&quot;">​</a></h3><p>所有 Agent 的抽象接口，定义三个核心方法：</p><ul><li><code>chat(input_data) → AsyncIterator[BaseOutput]</code> — 异步流式对话</li><li><code>handle_interrupt(heard_response)</code> — 处理用户打断</li><li><code>set_memory_from_history(conf_uid, history_uid)</code> — 从历史加载记忆</li></ul><h3 id="memoryagent" tabindex="-1">MemoryAgent <a class="header-anchor" href="#memoryagent" aria-label="Permalink to &quot;MemoryAgent&quot;">​</a></h3><p>MemoryAgent 是 VTuber 链路的<strong>编排器</strong>，职责是将 <code>AgentCore</code> 的 token 流接入 TTS / Live2D pipeline：</p><table tabindex="0"><thead><tr><th>组件</th><th>职责</th></tr></thead><tbody><tr><td><code>AgentCore</code></td><td>tool calling / vision / prompt / chat LLM / 历史存储</td></tr><tr><td><code>MemoryStore</code></td><td>维护对话 memory + 历史持久化</td></tr><tr><td><code>MessageFactory</code></td><td>构造 / 解析 OpenAI 格式消息（含多图）</td></tr><tr><td>Transformers 管线</td><td>断句 → 表情提取 → TTS 过滤 → 显示处理</td></tr></tbody></table><p>MemoryAgent 本身<strong>不做 LLM 调用</strong>，所有生成逻辑委托给 <code>AgentCore.run_turn()</code>。</p><h3 id="asyncllm" tabindex="-1">AsyncLLM <a class="header-anchor" href="#asyncllm" aria-label="Permalink to &quot;AsyncLLM&quot;">​</a></h3><p><code>stateless_llm/openai_compatible_llm.py</code> 提供两个核心方法：</p><table tabindex="0"><thead><tr><th>方法</th><th>用途</th></tr></thead><tbody><tr><td><code>chat_completion()</code></td><td>普通流式/非流式文本生成（不带工具）</td></tr><tr><td><code>stream_with_tools()</code></td><td>返回原始 <code>ChatCompletionChunk</code>，支持 text/tool_call delta 混合解析</td></tr><tr><td><code>vision_completion_once()</code></td><td>单次 vision 调用（图片摘要）</td></tr></tbody></table><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h2><p>一次完整对话请求的处理管线：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📥 BatchInput（用户输入）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>✉️ MessageFactory.extract_text_and_data_images()</span></span>
<span class="line"><span>    → user_text + user_images</span></span>
<span class="line"><span>    ↓ AgentCore.run_turn()</span></span>
<span class="line"><span>👁️ [has_images?] VisionSummarizer</span></span>
<span class="line"><span>    → vision_summaries（tool / upload 分开处理）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>📝 PromptBuilder.build()</span></span>
<span class="line"><span>    → UserPromptBlock（memory / diary / vision context 组合）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>🤖 chat_llm.stream_with_tools(messages, tools=schema)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>🔄 多轮循环（max 6 rounds）</span></span>
<span class="line"><span>    text delta    → yield str token（立刻流出）</span></span>
<span class="line"><span>    tool_call     → yield [🔧 name] → execute → append result → 继续</span></span>
<span class="line"><span>    finish=stop   → break</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>💾 ConversationStorage.append_turn()</span></span>
<span class="line"><span>    ↓ （MemoryAgent 侧）</span></span>
<span class="line"><span>🔄 Transformers 管线</span></span>
<span class="line"><span>    sentence_divider → actions_extractor → tts_filter → display_processor</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>📤 yield SentenceOutput (display_text, tts_text, actions)</span></span></code></pre></div><p><strong>关键节点：</strong></p><ul><li>👁️ 图片摘要根据模型能力决定（<code>chat_supports_vision=False</code> 时必须生成）</li><li>🤖 工具调用与文本生成同在一个 <code>chat_llm</code> 中，无独立 tool model</li><li>🔄 tool 执行期间 yield <code>[🔧 name]</code> 标签，保证用户不会看到空白等待</li><li>📤 输出是流式的，逐句 yield</li></ul><h2 id="模式矩阵" tabindex="-1">模式矩阵 <a class="header-anchor" href="#模式矩阵" aria-label="Permalink to &quot;模式矩阵&quot;">​</a></h2><p><code>AgentCore</code> 的行为由以下配置控制：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td><code>enable_tool</code></td><td>是否启用工具调用（<code>tools=schema</code> 传入 LLM）</td></tr><tr><td><code>chat_supports_vision</code></td><td>chat_llm 是否支持图片输入；否则必须先做 vision 摘要</td></tr><tr><td><code>require_detailed</code></td><td>是否对每张图片单独做详细摘要（True：逐图并发；False：一次多图）</td></tr></tbody></table><h2 id="不变量" tabindex="-1">不变量 <a class="header-anchor" href="#不变量" aria-label="Permalink to &quot;不变量&quot;">​</a></h2><ul><li><strong>History 不写 base64</strong>：<code>ConversationStorage</code> 只持久化纯文本内容</li><li><strong>Tool 图与用户图隔离</strong>：tool 回调图标签 <code>tool1</code>，与用户上传图 <code>p1/p2...</code> 语义分离</li><li><strong>MemoryAgent 不直接调 LLM</strong>：所有生成逻辑在 <code>AgentCore</code> 内部，MemoryAgent 只消费 token 流</li></ul>`,32)])])}const g=a(o,[["render",p]]);export{m as __pageData,g as default};
